setup.query:
#graphql
  mutation GiftCardCreateOmittedOptionalFields($input: GiftCardCreateInput!) {
    giftCardCreate(input: $input) {
      giftCard {
        id
        note
        expiresOn
        customer {
          id
        }
        templateSuffix
        recipientAttributes {
          message
          preferredName
          sendNotificationAt
          recipient {
            id
          }
        }
      }
      userErrors {
        field
        message
      }
    }
  }

readAfterCreate.query:
#graphql
  query GiftCardCreateOmittedOptionalFieldsRead($id: ID!) {
    giftCard(id: $id) {
      id
      note
      expiresOn
      customer {
        id
      }
      templateSuffix
      recipientAttributes {
        message
        preferredName
        sendNotificationAt
        recipient {
          id
        }
      }
    }
  }

cleanup.query:
#graphql
      mutation GiftCardCreateOmittedOptionalFieldsDeactivate($id: ID!) {
        giftCardDeactivate(id: $id) {
          giftCard {
            id
            enabled
            deactivatedAt
          }
          userErrors {
            field
            message
          }
        }
      }
